class Solution {
    public int longestPalindrome(String s, String t) {
        int n = s.length(), m = t.length();
        int[][] dp1 = new int[n + 1][n + 1], dp2 = new int[m + 1][m + 1];
        for (int i = n - 1; i >= 0; i--) {
            for (int j = i; j < n; j++) {
                dp1[i][j] = (s.charAt(i) == s.charAt(j)) ? (j - i + 1) : Math.max(dp1[i + 1][j], dp1[i][j - 1]);
            }
        }
        for (int i = m - 1; i >= 0; i--) {
            for (int j = i; j < m; j++) {
                dp2[i][j] = (t.charAt(i) == t.charAt(j)) ? (j - i + 1) : Math.max(dp2[i + 1][j], dp2[i][j - 1]);
            }
        }
        int res = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                res = Math.max(res, dp1[i][n - 1] + dp2[0][j]);
            }
        }
        return res;
    }
}
